// ============================================================
// NODO: Format_Fechas_YYYYMMDD
// Autor: Virtuoso IA Agency
// Version: 1.0  |  API Target: Cloudbeds v1.2
// ============================================================
// FUNCION: Validar campos, normalizar fechas a YYYY-MM-DD
//          y mapear room_type code a roomTypeID de Cloudbeds
// ============================================================

const body = $input.first().json.body || $input.first().json;

// --- 1. Validacion de campos obligatorios ---
const REQUIRED_FIELDS = ['first_name', 'last_name', 'email', 'checkin', 'checkout', 'room_type'];
const missing = REQUIRED_FIELDS.filter(f => !body[f] || String(body[f]).trim() === '');

if (missing.length > 0) {
  throw new Error('CAMPOS_FALTANTES | ' + missing.join(', '));
}

// --- 2. Validacion de formato de email ---
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(body.email)) {
  throw new Error('EMAIL_INVALIDO | Valor recibido: ' + body.email);
}

// --- 3. Normalizacion de fechas a YYYY-MM-DD ---
// Acepta: YYYY-MM-DD | MM/DD/YYYY | DD-MM-YYYY | timestamps Unix
function toYYYYMMDD(dateInput) {
  let d;
  const str = String(dateInput).trim();

  // Timestamp numerico (Unix ms)
  if (/^\d{10,13}$/.test(str)) {
    d = new Date(str.length === 10 ? parseInt(str) * 1000 : parseInt(str));
  }
  // Formato DD/MM/YYYY (comun en GHL)
  else if (/^\d{2}\/\d{2}\/\d{4}$/.test(str)) {
    const [dd, mm, yyyy] = str.split('/');
    d = new Date(`${yyyy}-${mm}-${dd}T12:00:00Z`);
  }
  // Formato YYYY-MM-DD o MM/DD/YYYY (nativo JS)
  else {
    d = new Date(str.includes('T') ? str : str + 'T12:00:00Z');
  }

  if (isNaN(d.getTime())) {
    throw new Error('FECHA_INVALIDA | No se pudo parsear: ' + dateInput);
  }

  const year  = d.getUTCFullYear();
  const month = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day   = String(d.getUTCDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

const checkin  = toYYYYMMDD(body.checkin);
const checkout = toYYYYMMDD(body.checkout);

// --- 4. Validacion logica de fechas ---
const msDay = 86400000;
const diffDays = (new Date(checkout) - new Date(checkin)) / msDay;

if (diffDays <= 0) {
  throw new Error('FECHA_LOGICA | checkout debe ser posterior a checkin. Diff: ' + diffDays + ' dias');
}
if (diffDays > 90) {
  throw new Error('FECHA_RANGO | Estadia mayor a 90 dias no permitida. Dias: ' + diffDays);
}
if (new Date(checkin) < new Date(new Date().toISOString().split('T')[0] + 'T00:00:00Z')) {
  throw new Error('FECHA_PASADA | checkin no puede ser en el pasado: ' + checkin);
}

// --- 5. Mapeo de Room Type Code -> Cloudbeds roomTypeID ---
// IMPORTANTE: Reemplazar los IDs con los IDs reales del Sandbox
// Obtener via: GET https://api.cloudbeds.com/api/v1.2/getRoomTypes?propertyID=XXX
const ROOM_TYPE_MAP = {
  'DQ': '{{ ROOM_TYPE_ID_DQ }}',  // Deluxe Queen  -- reemplazar con ID real
  'DK': '{{ ROOM_TYPE_ID_DK }}'   // Deluxe King   -- reemplazar con ID real
};

const roomCode = String(body.room_type).toUpperCase().trim();
const roomTypeID = ROOM_TYPE_MAP[roomCode];

if (!roomTypeID || roomTypeID.startsWith('{{')) {
  throw new Error('ROOM_TYPE_NO_MAPEADO | Codigo: ' + roomCode + ' | Opciones validas: DQ, DK');
}

// --- 6. Output estructurado para nodo HTTP Request ---
return [{
  json: {
    // --- Datos del huesped ---
    guestFirstName : body.first_name.trim(),
    guestLastName  : body.last_name.trim(),
    guestEmail     : body.email.trim().toLowerCase(),

    // --- Fechas normalizadas ---
    startDate      : checkin,
    endDate        : checkout,
    nightCount     : diffDays,

    // --- Habitacion ---
    roomTypeID     : roomTypeID,
    roomTypeCode   : roomCode,

    // --- Propiedad Cloudbeds Sandbox ---
    // IMPORTANTE: Reemplazar con propertyID real del Sandbox Virtuoso
    propertyID     : body.property_id || '{{ PROPERTY_ID_SANDBOX }}',

    // --- Parametros adicionales ---
    adults         : Math.max(1, parseInt(body.adults) || 1),
    children       : parseInt(body.children) || 0,
    source         : 'Virtuoso IA / GHL',
    status         : 'confirmed',

    // --- Metadata de trazabilidad ---
    _ghl_contact_id : body.contact_id || '',
    _raw_checkin    : body.checkin,
    _raw_checkout   : body.checkout,
    _processed_at   : new Date().toISOString()
  }
}];
